def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    for c in range(1, b + 2):
                        factor = ((ratio - a) ** 6) / ((a * b * c * 0.8) + 1)
                        priority += factor * np.sin(ratio * c / (a + 2)) * np.cos(b * ratio / (c + 1))
            priority += (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 2.1
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap * 2) * 7
            else:
                priority -= np.exp(-ratio * 2) * 5
        elif 5 < ratio <= 8:
            for x in range(2, int(np.ceil(ratio)) + 5):
                for y in range(1, x + 4):
                    term = ((ratio - x) ** 4) * np.cos(ratio * y) / (y + 1)
                    priority += np.tanh(term) * 1.7
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.5
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 6
            else:
                priority += np.sin(ratio * 3) * 3.3
        elif 2 <= ratio <= 5:
            s1 = 0
            for r in range(1, 18):
                s1 += ((ratio - 2) ** r) / (r * 2) * np.cos(r * ratio * 1.5)
            priority = (s1 * np.cos(5 * ratio)) - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1.9) ** m) / (m * 0.8)
            if bin_cap < item * 0.9:
                priority += np.sqrt(item / (bin_cap + 0.3)) * 5.2
            else:
                priority -= np.cos(30 * ratio) * 3.4
        elif 1 <= ratio < 2:
            s2 = 0
            for n in range(1, 13):
                s2 += ((2 - ratio) ** n) / (n ** 3 + 1)
            penalty = 0
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 4.8 + np.sin(15 * ratio) * 2.2
            else:
                penalty = np.cos(25 * ratio) * 3.1
            priority = s2 + penalty + np.exp(-1.7 / (ratio + 0.02))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 0.95) ** m) / m
        elif 0.5 <= ratio < 1:
            s3 = 0
            for v in range(1, 20):
                s3 += ((1 - ratio) ** v) / (v * 3)
            priority = s3
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.4) * 0.9
        elif 0.15 <= ratio < 0.5:
            s4 = 0
            for k in range(1, 16):
                s4 += ((0.5 - ratio) ** k) / (k * 5) * np.cos(k * ratio * 3)
            priority = s4 + 1 / (bin_cap + 5)
            if int(item * 1.5) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.1
            else:
                priority -= np.exp(-ratio * 1.7) * 4.5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s5 = 0
            for t in range(1, 13):
                s5 += ((0.15 - ratio) ** t) / (t * 8) * np.sin(t * item * 1.1)
            priority = s5 + 3 / (bin_cap + 5)
            if int(item * 0.6) % 7 == 0:
                priority *= 3.8
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.2
            else:
                priority -= np.exp(-ratio * 2.5) * 5.3
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.7
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 6.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.25) * 0.85
        else:
            priority -= np.cos(ratio * i * 1.25) * 0.85
        if i % 2 == 0:
            for w in range(1, 4):
                priority += np.tanh(np.sin(ratio * w * i) * w * 0.3)
        else:
            for w in range(1, 4):
                priority -= np.tanh(np.cos(ratio * w * i) * w * 0.3)
        priorities[i] = priority
    return priorities
